#!/usr/bin/env bash
# Verify that key plugin structure files exist.
# Generated by the initializer agent — edit to match your project.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"
FAIL=0

check_file() {
  if [ -f "$1" ]; then
    echo "OK   — $2"
  else
    echo "FAIL — $2 not found at $1"
    FAIL=1
  fi
}

check_dir() {
  if [ -d "$1" ]; then
    echo "OK   — $2"
  else
    echo "FAIL — $2 not found at $1"
    FAIL=1
  fi
}

echo "=== SDLC Domain Skill — Structure Verification ==="
echo ""

# Pre-existing plugin structure
check_file "$PROJECT_ROOT/plugins/harness/skills/harness/SKILL.md" "Main harness SKILL.md"
check_file "$PROJECT_ROOT/plugins/harness/skills/harness/references/patterns.md" "Shared patterns.md"
check_dir  "$PROJECT_ROOT/plugins/harness/skills/harness/roles" "Agent roles directory"

# SDLC skill file (F-001)
check_file "$PROJECT_ROOT/plugins/harness/skills/harness-sdlc/SKILL.md" "SDLC domain skill SKILL.md"

echo ""
if [ $FAIL -eq 0 ]; then
  echo "All checks passed."
else
  echo "Some checks failed — see above."
  exit 1
fi
